import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate, Link } from 'react-router-dom';
import { useFormik } from 'formik';
import { toast } from 'react-toastify';
import { loginCustomer, loginAdmin } from '../store/slices/authSlice';
import { loginSchema } from '../schemas';

export default function Login() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { loading } = useSelector(s => s.auth);
  const [isAdmin, setIsAdmin] = useState(false);

  const formik = useFormik({
    initialValues: { email: '', password: '' },
    validationSchema: loginSchema,
    onSubmit: async (values) => {
      const action = isAdmin ? loginAdmin(values) : loginCustomer(values);
      const result = await dispatch(action);
      if (result.meta.requestStatus === 'fulfilled') {
        toast.success('Login successful');
        navigate(isAdmin ? '/admin/dashboard' : '/dashboard');
      } else {
        toast.error(result.payload);
      }
    },
  });

  const inp = { padding: '14px 16px', borderRadius: 10, border: '1.5px solid #e2e8f0', fontSize: 16, width: '100%', boxSizing: 'border-box', outline: 'none', fontFamily: 'inherit', transition: 'border-color 0.15s' };
  const lbl = { fontSize: 14, fontWeight: 600, color: '#475569', display: 'block', marginBottom: 7 };
  const err = { color: '#ef4444', fontSize: 13, marginTop: 5 };

  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #1e293b 0%, #334155 100%)', padding: 24 }}>
      <div style={{ background: '#fff', borderRadius: 20, padding: '48px 52px', width: '100%', maxWidth: 460, boxShadow: '0 20px 60px rgba(0,0,0,0.25)' }}>
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <h1 style={{ color: '#1e293b', fontSize: 28, fontWeight: 800, margin: '0 0 6px' }}>MyFin Bank</h1>
          <p style={{ color: '#64748b', fontSize: 16 }}>Sign in to your account</p>
        </div>
        <div style={{ display: 'flex', gap: 8, marginBottom: 32, background: '#f1f5f9', borderRadius: 12, padding: 4 }}>
          {['Customer', 'Admin'].map(role => (
            <button key={role} type="button" onClick={() => setIsAdmin(role === 'Admin')} style={{ flex: 1, padding: '11px', borderRadius: 10, border: 'none', cursor: 'pointer', fontSize: 15, fontWeight: 600, background: (isAdmin ? role === 'Admin' : role === 'Customer') ? '#3b82f6' : 'transparent', color: (isAdmin ? role === 'Admin' : role === 'Customer') ? '#fff' : '#64748b', transition: 'all 0.15s' }}>
              {role}
            </button>
          ))}
        </div>
        <form onSubmit={formik.handleSubmit}>
          <div style={{ marginBottom: 20 }}>
            <label style={lbl}>Email Address</label>
            <input type="email" style={inp} placeholder="you@example.com" {...formik.getFieldProps('email')} onFocus={e => e.target.style.borderColor='#3b82f6'} onBlur={e => { e.target.style.borderColor='#e2e8f0'; formik.handleBlur(e); }} />
            {formik.touched.email && formik.errors.email && <div style={err}>{formik.errors.email}</div>}
          </div>
          <div style={{ marginBottom: 28 }}>
            <label style={lbl}>Password</label>
            <input type="password" style={inp} placeholder="Your password" {...formik.getFieldProps('password')} onFocus={e => e.target.style.borderColor='#3b82f6'} onBlur={e => { e.target.style.borderColor='#e2e8f0'; formik.handleBlur(e); }} />
            {formik.touched.password && formik.errors.password && <div style={err}>{formik.errors.password}</div>}
          </div>
          <button type="submit" disabled={loading} style={{ width: '100%', padding: '15px', borderRadius: 10, border: 'none', background: loading ? '#93c5fd' : '#3b82f6', color: '#fff', fontWeight: 700, fontSize: 16, cursor: loading ? 'not-allowed' : 'pointer' }}>
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>
        {!isAdmin && (
          <div style={{ textAlign: 'center', marginTop: 24, fontSize: 15, color: '#64748b' }}>
            <Link to="/forgot-password" style={{ color: '#3b82f6', fontWeight: 600 }}>Forgot Password?</Link>
            <span style={{ margin: '0 12px', color: '#cbd5e1' }}>|</span>
            <Link to="/register" style={{ color: '#3b82f6', fontWeight: 600 }}>Create Account</Link>
          </div>
        )}
      </div>
    </div>
  );
}
